urlset:
{# ── Pages principales ────────────────────────────────────────── #}


  https://meurtrehuisclos.fr/
  {{ "now"|date("Y-m-d") }}
  weekly
  1.0



  https://meurtrehuisclos.fr/telechargement
  {{ "now"|date("Y-m-d") }}
  monthly
  0.9



  https://meurtrehuisclos.fr/scenarios
  {{ "now"|date("Y-m-d") }}
  weekly
  0.9



  https://meurtrehuisclos.fr/packs
  {{ "now"|date("Y-m-d") }}
  monthly
  0.8



  https://meurtrehuisclos.fr/regles-du-jeu
  {{ "now"|date("Y-m-d") }}
  monthly
  0.7



  https://meurtrehuisclos.fr/a-propos
  {{ "now"|date("Y-m-d") }}
  yearly
  0.6



  https://meurtrehuisclos.fr/contact
  {{ "now"|date("Y-m-d") }}
  yearly
  0.5


{# ── Pages scénarios individuelles (trafic long tail) ─────────── #}
{# Le contrôleur passe : murderParties = MurderPartyRepository::findAll() #}

{% for murderParty in murderParties %}

  https://meurtrehuisclos.fr/scenarios/{{ murderParty.slug }}
  {{ murderParty.updatedAt is defined and murderParty.updatedAt ? murderParty.updatedAt|date("Y-m-d") : "now"|date("Y-m-d") }}
  monthly
  0.85

{% endfor %}

{# ── Pages packs individuelles ─────────────────────────────────── #}

{% for pack in packs %}

  https://meurtrehuisclos.fr/packs/{{ pack.slug }}
  {{ pack.updatedAt ? pack.updatedAt|date("Y-m-d") : "now"|date("Y-m-d") }}
  monthly
  0.75

{% endfor %}

{# ── Pages légales : exclues du sitemap (noindex ou crawl budget inutile) #}
{# /confidentialite, /cgv, /cgu, /mentions → à passer en noindex via robots meta #}
